import novamind_api as nm

# Check social posts about competitors
posts = nm.analytics.get_social_posts(days=30, limit=50)
print('=== Social Posts (Last 30 days) ===')
for p in posts['posts']:
    if 'competitor' in p['content'].lower() or 'quantum' in p['content'].lower() or 'edge' in p['content'].lower() or 'rival' in p['content'].lower() or 'launch' in p['content'].lower():
        print(f'  [{p["day"]}] {p["content"][:120]}...')
    elif 'quality' in p['content'].lower() or 'expect' in p['content'].lower():
        print(f'  [{p["day"]}] Q-REL: {p["content"][:120]}...')
    elif 'waiting' in p['content'].lower() or 'support' in p['content'].lower() or 'ticket' in p['content'].lower():
        print(f'  [{p["day"]}] SUPPORT: {p["content"][:120]}...')

# Check costs  
info = nm.infrastructure.get_cost_info()
print('\n=== Capacity Costs ===')
print(f'Current capacity tier: cost=${info.get("current_tier_cost")}, compute_cost_per_unit={info.get("compute_cost_per_unit")}')
for t in info.get('tiers', []):
    print(f'  Tier {t["tier"]}: ${t["cost"]:.0f}/day, compute=${t["compute_cost"]:.4f}/unit, capacity={t["capacity"]}')

# Check if we can get group-specific detail
for gid in ['S1']:
    ginfo = nm.market.get_group_insights(group_id=gid)
    print(f'\n=== {gid} Insights ===')
    for k in ['info_level', 'group_id']:
        print(f'  {k}: {ginfo.get(k)}')
